const axios = require('axios');
const cheerio = require('cheerio');

async function getStackOverflowLinks(searchTerm) {
  const url = `https://stackoverflow.com/search?q=${searchTerm}`;
  const { data } = await axios.get(url);
  const $ = cheerio.load(data);

  const linkElements = $('.s-post-summary--content a');
  const linkUrls = [];

  linkElements.each((_, el) => {
    const href = $(el).attr('href');
    const url = new URL(href, 'https://stackoverflow.com').href;
    linkUrls.push(url);
  });

  return linkUrls;
}

// Example usage:
getStackOverflowLinks('remove item in array')
  .then(urls => console.log(urls))
  .catch(error => console.error(error));
```

